mapper.select:
SELECT p.no, p.writer_id, m.nickname AS writer_nickname,
       p.title, p.content, p.role_type, p.tier, p.mic_yn, p.main_hero, p.status,
       TO_CHAR(p.reg_date, 'yyyy-mm-dd hh24:mi') AS reg_date
  FROM ow_party p
  JOIN ow_member m ON p.writer_id = m.id
 WHERE 1 = 1
 AND p.role_type = #{roleType} 
         AND p.tier      = #{tier}     
       AND p.mic_yn    = #{micYn}    
     AND p.status    = #{status}   
 ORDER BY p.no DESC
